import json
b = json.load(open('baseline-packages.json'))
a = json.load(open('after-cpm-packages.json'))
for bp, ap in zip(b['projects'], a['projects']):
    name = bp['path'].split('/')[-1]
    bpkgs = {pkg['id']: pkg['resolvedVersion'] for fw in bp['frameworks'] for pkg in fw['topLevelPackages']}
    apkgs = {pkg['id']: pkg['resolvedVersion'] for fw in ap['frameworks'] for pkg in fw['topLevelPackages']}
    if bpkgs == apkgs:
        print(f'{name}: MATCH')
    else:
        print(f'{name}: MISMATCH - before={bpkgs} after={apkgs}')
"

